 1	import React from 'react';
 2	import { useTranslation } from 'react-i18next';
 3	import { EmptyState, EmptyStateBody, EmptyStateIcon, EmptyStateVariant, Title } from '@patternfly/react-core';
 4	import { ExclamationCircleIcon } from '@patternfly/react-icons';
 5	import { helpers } from '../../helpers';
 6	
 7	interface ErrorMessageProps {
 8	  description?: string;
 9	  title?: string;
10	}
11	
12	const ErrorMessage: React.FC<ErrorMessageProps> = ({ description, title }) => {
13	  const { t } = useTranslation();
14	  return (
15	    <EmptyState variant={EmptyStateVariant.full}>
16	      <EmptyStateIcon icon={ExclamationCircleIcon} />
17	      <Title headingLevel="h2" size="lg">
18	        {title || t('view.error', { context: 'title', appName: helpers.UI_NAME })}
19	      </Title>
20	      <EmptyStateBody>{description || t('view.error', { context: 'description' })}</EmptyStateBody>
21	    </EmptyState>
22	  );
23	};
24	
25	export { ErrorMessage as default, ErrorMessage, type ErrorMessageProps };

